-- ── Backlog ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Backlog is a project management and bug-tracking platform from Nulab that combines task management, Kanban boards, Gantt charts, and built-in Git and Subversion repositories for software and cross-functional teams.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; paid plans start at $35/month (Starter)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Roughly 200 employees company-wide (Nulab Inc.; estimate, varies by source)$q$, company_size),
  headquarters = COALESCE($q$Fukuoka, Japan (Nulab Inc.), with additional offices in Tokyo, Kyoto, New York, and Amsterdam$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Backlog by Nulab Review 2026: Features, Pricing, Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Backlog combines task tracking, Kanban boards, Gantt charts, and Git/SVN hosting. See 2026 pricing, features, pros, cons, and who it fits best.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Backlog is a web-based project management and issue-tracking tool built by Nulab Inc., a Japanese software company founded in 2004 and headquartered in Fukuoka, Japan. Backlog itself was first released in Japan in 2005 and launched in English for a global audience in 2011. It targets software teams and cross-functional teams (marketing, design, operations) that want task management, Kanban-style boards, Gantt charts, burndown charts, wikis, and file storage bundled with built-in Git and Subversion repository hosting in one product, positioning it as an alternative to pairing Jira with a separate code host. According to Nulab press materials, Backlog has surpassed 10,000 paying customers and over 1.7 million registered users worldwide. Pricing is freemium: a Free plan supports up to 10 users, 1 project, and 100MB of storage. Paid tiers are Starter ($35/month, 30 users, 5 projects, 1GB storage, subtasking), Standard ($100/month, unlimited users, 100 projects, 30GB storage, Gantt and burndown charts, issue templates), Premium ($175/month, unlimited projects, 100GB storage, unlimited-range Gantt view, custom fields, and a bundled AI Assistant with 2,000 monthly credits), and a custom-priced Enterprise tier adding SAML single sign-on, SCIM user provisioning, audit logs, and a dedicated customer success manager. Notably, Backlog does not charge per-user fees on its higher tiers, which differentiates its pricing model from many project management competitors. Core features include Kanban and list-view boards, Gantt charts, burndown charts, custom issue statuses and workflows, subtasking, wikis, file attachments, integrated Git/SVN repositories with pull-request code review, watch and notification systems, and native mobile apps for iOS and Android. Nulab also makes complementary products, including Cacoo for diagramming and Typetalk for team chat, which integrate with Backlog. Backlog competes most directly with Jira, Trello, Asana, and ClickUp, and is frequently chosen by teams wanting a flatter learning curve than Jira while still supporting developer workflows like in-app code review. Nulab maintains offices in Fukuoka (headquarters), Tokyo, Kyoto, New York, Amsterdam, and Singapore. Exact current total employee counts vary by source (LinkedIn lists 51-200, PitchBook reports approximately 207), so this figure should be treated as an approximation rather than an exact number.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b8ac237-4025-433b-86e2-003f6116e259';

