-- ── BasKet Note Pads ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BasKet Note Pads is a free, open-source note-organizing application, originally built for KDE on Linux, that lets users collect text, images, links, and files into hierarchical, scrapbook-style baskets.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BasKet Note Pads: Free Open-Source Notes App (2026 Guide)$q$, seo_title),
  seo_meta_description = COALESCE($q$BasKet Note Pads is a free, open-source KDE note organizer for text, images, links and files. See features, history, and current 2026 status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BasKet Note Pads, commonly written as Basket, is a free and open-source note-organizing application originally created for the KDE desktop environment on Linux. Copyright notices in the project date to 2003-2006 under original author Sebastien Laout, indicating the project began around 2003, and it was designed conceptually as a KDE equivalent to the classic Mac scrapbook-style note tool DropDrawers. The application lets users collect and organize free-form information, including plain text, rich text, images, links, email addresses, files, application launchers, and even colors picked from the screen, into 'baskets' that can be nested hierarchically by topic or project, similar to a digital scrapbook or bulletin board rather than a strictly linear notebook. Notes within a basket can be laid out automatically in columns or positioned freely by the user. The application also supports tagging notes with labels such as Important, Information, Idea, Work, or Personal, and supports multi-state tags that function as checkboxes for to-do lists, progress bars, or priority indicators. BasKet can import data from several other note applications, including KNotes, KJots, KnowIt, TuxCards, Sticky Notes, and Tomboy, which made it a common migration target for Linux users consolidating scattered notes. The project is licensed under the GNU General Public License version 2 (GPLv2) and its source code is publicly available, including a maintained mirror on GitHub under the KDE organization and a community fork at basket-notepads.github.io. Development slowed for a period as KDE moved from KDE 4 to Plasma/KDE Frameworks, but the project has seen renewed activity, including a rewrite targeting Qt6 and KDE Frameworks 6, and it remains listed on the official KDE Store and KDE Applications catalog as of the most recent available information. As a community-maintained open-source project rather than a commercial product, BasKet has no company, headquarters, or formal pricing; it is free to download and use, and its ongoing development depends on volunteer contributors rather than a dedicated business. Exact current maintenance activity levels and release cadence should be verified directly against the project's GitHub repository for anyone relying on up-to-the-day status.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dd3835c7-4555-46b1-a75d-55532c70e333';

