-- ── Bastet ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bastet is a free, open-source, ncurses-based falling-block puzzle game for Linux and Unix terminals that deliberately gives players the worst possible piece instead of a random one, making it intentionally harder than standard Tetris-style games.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bastet: The Evil Terminal Tetris Clone (2026 Guide)$q$, seo_title),
  seo_meta_description = COALESCE($q$Bastet is a free open-source terminal Tetris clone that deliberately gives you the worst piece. See how it works, features, and where to get it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bastet, short for 'bastard tetris', is a free and open-source, ncurses-based falling-block puzzle game for Linux and Unix terminals, created by Federico Poloni. It is functionally similar to Tetris, but instead of choosing the next piece at random, Bastet deliberately uses a scoring algorithm to select the worst possible piece for the player's current board state, intentionally making the game harder and more frustrating than standard Tetris-style clones. Bastet's own tagline describes it as an attractive alternative to Microsoft Word for people who enjoy swearing at their computer. The game offers two modes: a 'normal' mode that still shows a preview of the next piece (with the adversarial algorithm working around that preview), and a 'harder' mode that hides the next-piece preview entirely, in which the piece-selection algorithm is further tuned to exploit the lack of a preview. According to the project's own release history, the piece-selection algorithm evolved over multiple versions, from an initial approach in early releases (version 0.37 was the first public release) to a more sophisticated rewritten algorithm in version 0.43 (2009) that also included a correction mechanism to avoid selecting the same piece too many times in a row, which would otherwise make the adversarial pattern too obvious or 'implausible' to players. The most recent versions found in the project's public source history are in the 0.43.x range, with a tagged release (0.43.2) from June 2017; a Slashdot community post about the game titled 'Bastard Tetris Hates You' dates to April 2005, indicating the game already existed and had a public following by that time, though an exact founding or first-release year could not be independently confirmed and should not be treated as certain. Bastet is released under the GNU General Public License version 3 (GPLv3), and its source code (written primarily in C++) is publicly hosted on GitHub under the fph/bastet repository, which as of research had over 300 stars and dozens of forks, reflecting a modest but persistent following among terminal and retro-gaming enthusiasts. The game is packaged in most major Linux distributions' repositories and is also portable to other Unix-like systems and, per some packaging notes, Windows and macOS via ncurses-compatible environments. As a solo open-source hobby project rather than a commercial product, Bastet has no company, headquarters, employee count, or pricing plans; it is entirely free.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '64d33f3f-8232-479c-8b76-920a41e078aa';

