-- ── BBEdit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BBEdit is a long-running macOS text and code editor from Bare Bones Software, known for powerful grep-based search and multi-file text manipulation, offered with a genuinely usable free mode alongside paid subscription and one-time license options.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Free Mode); paid plans from $4.99/month or $49.99/year$q$, starting_price),
  founded_year = COALESCE(1992, founded_year),
  company_size = COALESCE($q$Small, privately held company (exact employee count not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$North Chelmsford, Massachusetts, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BBEdit Review 2026: Features, Pricing, Free Mode Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$BBEdit is Bare Bones Software's macOS text and code editor. See 2026 pricing (Free Mode, subscription, one-time license), features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BBEdit is a macOS-native text and code editor made by Bare Bones Software, Inc., a privately held company founded by developer Rich Siegel. BBEdit was first released as freeware in 1992, originally intended as a demonstration of an experimental Pascal compiler for the Macintosh, before becoming a commercial product; Bare Bones Software itself was formally founded in May 1993 and incorporated in Massachusetts in June 1994. The company's own copyright notices span '1992-2026', reflecting over three decades of continuous development, and it is headquartered in North Chelmsford, Massachusetts. BBEdit has long marketed itself with the tagline 'It doesn't suck,' a registered trademark, emphasizing reliability and depth of text-manipulation features over flashiness. Its feature set includes powerful grep-based pattern search and replace across single files or entire multi-file projects, syntax coloring for a wide range of programming and markup languages, code folding, function/symbol navigation, FTP and SFTP file access, integrated Git and Subversion support, AppleScript and Unix shell scripting hooks, text and code completion, and dedicated HTML authoring tools. As of the most recent pricing found, BBEdit uses a mixed pricing model: a 'Free Mode' that unlocks automatically after a 30-day full trial period and can be used indefinitely at no cost with a reduced feature set (Bare Bones states there are no nag screens in this mode), plus paid access via a Mac App Store subscription (reported at $4.99 per month or $49.99 per year) or a traditional one-time commercial license purchased through Bare Bones' own online store, with upgrade pricing available for owners of older commercial licenses (BBEdit 15.5.5 or earlier was referenced as the upgrade-eligible baseline in current documentation). BBEdit requires macOS 14.0 or later in its current version and ships as a universal binary supporting both Intel and Apple silicon Macs. It is widely regarded within the Mac developer and technical writing community as one of the most durable and well-regarded text editors in the platform's history, competing today with editors like Sublime Text, Visual Studio Code, and Nova. Precise current company size (employee count) is not publicly disclosed, consistent with Bare Bones Software's status as a small, privately held software company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5d754571-a7ce-46cf-a42b-c0a05ee72625';

