  seo_title = COALESCE($q$Beanstalk Review 2026: Git/SVN Hosting and Deployment Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Beanstalk is Wildbit's Git and SVN hosting platform with code review and automated deployment. See 2026 pricing, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Beanstalk, at beanstalkapp.com, is a hosted Git and Subversion (SVN) platform that combines source code hosting, code review, and automated deployment in one product. It is made by Wildbit, LLC, a privately held, bootstrapped software company founded in 1999 and headquartered in Philadelphia, Pennsylvania; Wildbit describes itself as profitable, debt-free, and privately owned, and it is also known for other products such as the transactional email service Postmark. Beanstalk itself launched in 2007, making it one of the older continuously operating players in the hosted version-control and deployment space, predating many later entrants that focused purely on Git after GitHub's own 2008 launch; Beanstalk notably supports both Git and Subversion, which some newer competitors do not. According to Beanstalk's own marketing materials, over 100,000 companies, ranging from small teams to larger organizations, have used the service since its 2007 launch. Core functionality includes in-browser code browsing and editing, branch management, repository and branch-level permissions, code review with issue tracking and discussion threads and coverage statistics, and deployment automation supporting multiple environments and targets including FTP, SFTP, shell-based servers, Cloud Files, Heroku, Amazon S3, and DreamObjects, along with release notes and deployment notifications; older integrations reference webhook support for chat tools like HipChat and Campfire, which reflects the product's long operating history and may indicate some older integrations are legacy rather than currently emphasized. Security features include stated bank-level encryption, two-step (two-factor) authentication, and SOC 1 Type 2 compliance. Pricing follows a subscription model with a free account offering 100MB of storage, 1 repository, and 1 user (no credit card required), and paid tiers beginning with Bronze at $15/month (3GB storage, 10 repositories, 5 users, 3 deployment servers per repository) and Silver at $25/month (6GB, 25 repositories, 20 users, 5 servers per repository), followed by higher enterprise-oriented tiers Gold ($50/month), Platinum ($100/month), and Diamond ($200/month), which add security tooling, IP restrictions, simultaneous multi-server deployments, and a stated 100 percent uptime SLA; annual billing offers a discount, and custom storage is available above the Diamond tier by request. As of the research date, beanstalkapp.com, its pricing page, and its status page were all live and displaying current-looking pricing and functionality, supporting that the service continues to operate, though this is based on the website being reachable rather than independently confirmed recent usage or company financial disclosures.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e68d6b56-cd53-4fcd-896a-94f7affcdd1d';

