-- ── Bearer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bearer is a developer-first static application security testing (SAST) tool for finding sensitive data flows and security risks in source code; it was acquired by Cycode in 2024 and its scanning engine now powers Cycode's ASPM platform, though the open-source Bearer CLI remains available.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source CLI); Cloud/enterprise pricing via Cycode is custom$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Originally Clichy, France (Paris region); Bearer's team and technology are now part of Cycode$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bearer Review 2026: SAST Tool, Cycode Acquisition, Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Bearer is a developer-first SAST tool for sensitive data and security risks in code, now part of Cycode. See 2026 status, features, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bearer is a developer-first static application security testing (SAST) tool, originally built by a company also called Bearer, founded in 2018 by Guillaume Montard (CEO) and Cedric Fabianski, and headquartered near Paris, in Clichy, France. Bearer raised seed funding from investors including Alven, Kima Ventures, Partech, and Point Nine, with a reported total of 8 million dollars in equity financing across its seed rounds, including a second tranche announced in October 2022. The core product is the Bearer CLI, an open-source scanner that analyzes source code to discover, filter, and prioritize security and privacy risks, with particular emphasis on identifying flows of sensitive data such as personally identifiable information (PII) and protected health information (PHI) through an application's codebase, aimed at helping developers catch risky data handling before it reaches production. In March 2024, application security company Cycode announced it was acquiring Bearer, with the deal closing on April 30, 2024, explicitly framed as accelerating Cycode's move into AI-enhanced security remediation. As a result of the acquisition, Bearer's scanning engine, privacy-analysis capabilities, and engineering team moved into Cycode, and Bearer's technology now powers capabilities within Cycode's Application Security Posture Management (ASPM) platform. Bearer is no longer an independently operating company; its original bearer.sh website now redirects to bearer.com, which presents Bearer as a Cycode product rather than a standalone company. The Bearer CLI itself remains available and free, released under the Elastic License v2 (ELv2), and continues to receive active updates, evidenced by version releases into 2026, supporting languages including Ruby, JavaScript, TypeScript, Java, and PHP, and integrating with GitHub, GitLab, and Bitbucket for CI/CD pipeline scanning. Beyond the free CLI, more advanced capabilities, described as 'Bearer Pro' and offered through the broader Cycode ASPM platform, add cross-file and interprocedural analysis and support for additional languages such as C#, Kotlin, and Elixir; this paid tier is sold as part of Cycode's enterprise offering rather than as a standalone Bearer subscription, and Cycode does not publish self-service list pricing for it, consistent with typical enterprise security sales motions. In short, for anyone evaluating 'Bearer' in 2026, the correct framing is: independently-operating startup status ended in 2024 via acquisition, but the product itself (both the free open-source CLI and a paid enterprise tier) continues to exist and be actively developed under Cycode's ownership.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '102885a9-d27e-4d24-8bcd-26a67c8bc64f';

